        .block,
        .criteria {
            display: inline-block;
            width: 30px;
            height: 30px;
            vertical-align: middle;
            text-align: center;
            border: 1px solid black;
            padding: 3px;
        }

        .criteria {
            border: none;
            width: 100px;
        }

        .red {
            background-color: indianred;
